/** Strip accents + lowercase for accent-insensitive search. */
function fold(value: string): string {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim()
}

/**
 * Concelhos whose name or district matches every whitespace-separated term in
 * the query (accent-insensitive), name-sorted, capped at `limit`. Empty query
 * returns the first `limit` concelhos.
 */
export function searchConcelhos(query: string, limit = 8): ConcelhoEntry[] {
  const terms = fold(query).split(/\s+/).filter(Boolean)
  if (terms.length === 0) return CONCELHOS.slice(0, limit)
  const result: ConcelhoEntry[] = []
  for (const c of CONCELHOS) {
    const hay = fold(c.name + " " + c.district)
    if (terms.every((t) => hay.includes(t))) {
      result.push(c)
      if (result.length >= limit) break
    }
  }
  return result
}

/** Exact DICO lookup, or null. */
export function concelhoByDico(dico: string): ConcelhoEntry | null {
  return CONCELHOS.find((c) => c.dico === dico) ?? null
}

