/**
 * Accent-insensitive lookup by concelho name (incidents carry the name, not a
 * DICO). Returns null when the name isn't in the mainland concelho set (islands,
 * spelling drift). Used to link an incident's concelho to its profile page.
 */
export function concelhoByName(name: string): ConcelhoEntry | null {
  return BY_FOLDED_NAME.get(fold(name)) ?? null
}
